// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  // Helper function to get weather icon based on condition
  const getWeatherIcon = (condition: string): string => {
    const lowerCondition = condition.toLowerCase();
    if (lowerCondition.includes('sunny') || lowerCondition.includes('clear')) return '☀️';
    if (lowerCondition.includes('cloudy') || lowerCondition.includes('overcast')) return '☁️';
    if (lowerCondition.includes('rainy') || lowerCondition.includes('rain')) return '🌧️';
    if (lowerCondition.includes('snow')) return '❄️';
    if (lowerCondition.includes('storm') || lowerCondition.includes('thunder')) return '⛈️';
    if (lowerCondition.includes('windy') || lowerCondition.includes('wind')) return '💨';
    if (lowerCondition.includes('fog') || lowerCondition.includes('mist')) return '🌫️';
    return '🌤️';
  };

  const weatherIcon = getWeatherIcon(props.condition);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main Weather Card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Header with City Name */}
            <Row align="center" justify="between">
              <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' })}
              </Text>
            </Row>

            <Divider />

            {/* Temperature Section */}
            <Row align="center" gap="var(--ggui-spacing-4)" justify="start">
              <Box>
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                  {Math.round(props.temperature)}°{props.unit}
                </Text>
              </Box>
              <Box>
                <Text size="3xl" color="var(--ggui-color-primary-500)">{weatherIcon}</Text>
              </Box>
              <Stack gap="var(--ggui-spacing-1)">
                <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                  {props.condition}
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Feels like {Math.round(props.temperature - 2)}°{props.unit}
                </Text>
              </Stack>
            </Row>

            <Divider />

            {/* Humidity and Wind Speed */}
            <Row gap="var(--ggui-spacing-4)" justify="between" align="stretch">
              <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={false} style={{ flex: 1, background: 'var(--ggui-color-surfaceVariant)' }}>
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  <Icon name="droplets" size={24} color="var(--ggui-color-primary-500)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text size="xl" weight="bold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Card>

              <Card shadow="sm" padding="var(--ggui-spacing-4)" radius="md" border={false} style={{ flex: 1, background: 'var(--ggui-color-surfaceVariant)' }}>
                <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                  <Icon name="wind" size={24} color="var(--ggui-color-primary-500)" />
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text size="xl" weight="bold" color="var(--ggui-color-onSurface)">{Math.round(props.windSpeed)} km/h</Text>
                </Stack>
              </Card>
            </Row>
          </Stack>
        </Card>

        {/* 5-Day Forecast */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
          <Row gap="var(--ggui-spacing-3)" wrap align="center" justify="start">
            {props.forecast && props.forecast.length > 0 ? (
              props.forecast.map((day, index) => {
                const dayIcon = day.icon ? getWeatherIcon(day.icon) : '🌤️';
                const dayName = day.day || ['Mon', 'Tue', 'Wed', 'Thu', 'Fri'][index % 5] || `Day ${index + 1}`;
                return (
                  <Card
                    key={index}
                    shadow="sm"
                    padding="var(--ggui-spacing-4)"
                    radius="md"
                    border={true}
                    style={{ flex: '0 1 calc(20% - var(--ggui-spacing-2))', minWidth: '120px' }}
                  >
                    <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
                      <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">
                        {dayName}
                      </Text>
                      <Text size="2xl" color="var(--ggui-color-primary-500)">{dayIcon}</Text>
                      <Stack gap="var(--ggui-spacing-1)" align="center">
                        <Text size="sm" weight="semibold" color="var(--ggui-color-onSurface)">
                          {day.high !== undefined ? Math.round(day.high) : '—'}°
                        </Text>
                        <Text size="sm" color="var(--ggui-color-onSurfaceVariant)">
                          {day.low !== undefined ? Math.round(day.low) : '—'}°
                        </Text>
                      </Stack>
                    </Stack>
                  </Card>
                );
              })
            ) : (
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                No forecast data available
              </Text>
            )}
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}

// DO NOT EDIT imports — all available components are pre-imported.
// prettier-ignore-start
import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State for multi-step form
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation errors
  const [nameError, setNameError] = useState('');
  const [emailError, setEmailError] = useState('');

  // Email validation helper
  const isValidEmail = (email: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(email);
  };

  // Validate step 1
  const validateStep1 = (): boolean => {
    let isValid = true;
    if (!name.trim()) {
      setNameError('Name is required');
      isValid = false;
    } else {
      setNameError('');
    }
    if (!email.trim()) {
      setEmailError('Email is required');
      isValid = false;
    } else if (!isValidEmail(email)) {
      setEmailError('Please enter a valid email address');
      isValid = false;
    } else {
      setEmailError('');
    }
    return isValid;
  };

  // Check if step 1 is valid (for Next button)
  const isStep1Valid = (): boolean => {
    return name.trim() !== '' && email.trim() !== '' && isValidEmail(email);
  };

  // Check if step 2 is valid
  const isStep2Valid = (): boolean => {
    return satisfaction !== '';
  };

  // Handle Next button
  const handleNext = (): void => {
    if (currentStep === 1) {
      if (validateStep1()) {
        setCurrentStep(2);
      }
    } else if (currentStep === 2) {
      setCurrentStep(3);
    } else if (currentStep === 3) {
      setCurrentStep(4);
    }
  };

  // Handle Back button
  const handleBack = (): void => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  // Handle feature selection
  const handleFeatureChange = (feature: string): void => {
    setSelectedFeatures((prev) =>
      prev.includes(feature)
        ? prev.filter((f) => f !== feature)
        : [...prev, feature]
    );
  };

  // Handle submission
  const handleSubmit = (): void => {
    const satisfactionIndex = parseInt(satisfaction, 10);
    submit({
      name,
      email,
      satisfaction: satisfactionIndex,
      features: selectedFeatures,
      comments,
    });
  };

  // Calculate progress percentage (for 4 total steps)
  const progressPercentage = (currentStep / 4) * 100;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Box>
          <Heading level={1} color="var(--ggui-color-onSurface)">Multi-Step Survey</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" style={{ marginTop: 'var(--ggui-spacing-2)' }}>
            Step {currentStep} of 4
          </Text>
        </Box>

        {/* Progress Bar */}
        <Progress value={progressPercentage} max={100} variant="default" size="md" showLabel={false} />

        {/* Step 1: Name & Email */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Personal Information</Heading>
              <Input
                label="Name"
                placeholder="Enter your name"
                value={name}
                onChange={setName}
                error={nameError}
                required
              />
              <Input
                label="Email"
                type="email"
                placeholder="you@example.com"
                value={email}
                onChange={setEmail}
                error={emailError}
                required
              />
            </Stack>
          </Card>
        )}

        {/* Step 2: Satisfaction Rating */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">How satisfied are you?</Heading>
              <RadioGroup
                label="Satisfaction Rating"
                value={satisfaction}
                onChange={setSatisfaction}
                direction="vertical"
                options={props.satisfactionLabels.map((label, idx) => ({
                  value: String(idx + 1),
                  label,
                }))}
              />
            </Stack>
          </Card>
        )}

        {/* Step 3: Feature Interests */}
        {currentStep === 3 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Which features interest you?</Heading>
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Select all that apply</Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={selectedFeatures.includes(feature)}
                    onChange={() => handleFeatureChange(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Step 4: Comments */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={2} color="var(--ggui-color-onSurface)">Additional Comments</Heading>
              <TextArea
                label="Comments"
                placeholder="Share any additional feedback (optional)"
                value={comments}
                onChange={setComments}
                rows={6}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}

        {/* Review Step (shown after step 4 in a summary) */}
        {currentStep === 4 && (
          <Card padding="var(--ggui-spacing-6)" shadow="sm" border={true}>
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={3} color="var(--ggui-color-onSurface)">Review Your Answers</Heading>
              <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Name</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">{name}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Email</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">{email}</Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Satisfaction</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">
                  {props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}
                </Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Features of Interest</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">
                  {selectedFeatures.length > 0 ? selectedFeatures.join(', ') : 'None selected'}
                </Text>
              </Box>
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Comments</Text>
                <Text variant="body" color="var(--ggui-color-onSurface)">
                  {comments || '(No comments)'}
                </Text>
              </Box>
            </Stack>
          </Card>
        )}

        {/* Navigation Buttons */}
        <Row gap="var(--ggui-spacing-3)" justify="end" align="center">
          {currentStep > 1 && (
            <Button variant="outline" onClick={handleBack}>
              Back
            </Button>
          )}
          {currentStep < 4 && (
            <Button
              variant="primary"
              onClick={handleNext}
              disabled={(currentStep === 1 && !isStep1Valid()) || (currentStep === 2 && !isStep2Valid())}
            >
              Next
            </Button>
          )}
          {currentStep === 4 && (
            <Button variant="primary" onClick={handleSubmit}>
              Submit Survey
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

