import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Category color mapping
const categoryColorMap: Record<string, { bg: string; text: string }> = {
  'nonmetal': { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-700)' },
  'noble-gas': { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-700)' },
  'halogen': { bg: 'var(--ggui-color-warning-100)', text: 'var(--ggui-color-warning-700)' },
  'alkali-metal': { bg: 'var(--ggui-color-info-100)', text: 'var(--ggui-color-info-700)' },
  'alkaline-earth-metal': { bg: 'var(--ggui-color-primary-200)', text: 'var(--ggui-color-primary-800)' },
  'transition-metal': { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-700)' },
  'lanthanide': { bg: 'var(--ggui-color-primary-300)', text: 'var(--ggui-color-primary-900)' },
  'actinide': { bg: 'var(--ggui-color-warning-200)', text: 'var(--ggui-color-warning-900)' },
  'metalloid': { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' },
  'post-transition-metal': { bg: 'var(--ggui-color-outline)', text: 'var(--ggui-color-surface)' },
};

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

export default function Component(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  // Filter elements based on search query
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) {
      return props.elements;
    }
    const query = searchQuery.toLowerCase();
    return props.elements.filter(el => {
      const matchesName = el.name?.toLowerCase().includes(query);
      const matchesSymbol = el.symbol?.toLowerCase().includes(query);
      return matchesName || matchesSymbol;
    });
  }, [searchQuery, props.elements]);

  // Get unique categories from elements
  const categories = useMemo(() => {
    const cats = new Set<string>();
    props.elements.forEach(el => {
      if (el.category) cats.add(el.category);
    });
    return Array.from(cats).sort();
  }, [props.elements]);

  const getElementColor = (category?: string) => {
    if (!category) return { bg: 'var(--ggui-color-surface)', text: 'var(--ggui-color-onSurface)' };
    return categoryColorMap[category] || { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' };
  };

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6)" center={false}>
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-4)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <SearchField
            value={searchQuery}
            onChange={setSearchQuery}
            placeholder="Search by name or symbol (case-insensitive)"
            size="md"
          />
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">LEGEND</Text>
            <Row gap="var(--ggui-spacing-4)" wrap>
              {categories.map(category => {
                const colors = getElementColor(category);
                return (
                  <Row key={category} gap="var(--ggui-spacing-2)" align="center">
                    <Box
                      padding="var(--ggui-spacing-2)"
                      background={colors.bg}
                      borderRadius="var(--ggui-shape-radius-sm)"
                      style={{ minWidth: '20px', height: '20px' }}
                    />
                    <Text variant="bodySmall">{category}</Text>
                  </Row>
                );
              })}
            </Row>
          </Stack>
        </Card>

        {/* Grid container */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
            padding: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surfaceVariant)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
          }}
        >
          {filteredElements.map((element) => {
            if (!element.symbol || !element.row || !element.col) return null;
            const colors = getElementColor(element.category);
            const isSelected = selectedElement?.atomicNumber === element.atomicNumber;
            return (
              <Card
                key={element.atomicNumber}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                padding="var(--ggui-spacing-2)"
                shadow={isSelected ? 'md' : 'sm'}
                radius="md"
                border={isSelected}
                style={{
                  gridRow: element.row,
                  gridColumn: element.col,
                  background: colors.bg,
                  color: colors.text,
                  cursor: 'pointer',
                  textAlign: 'center',
                  minHeight: '80px',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  alignItems: 'center',
                  padding: 'var(--ggui-spacing-3)',
                  border: isSelected ? '2px solid var(--ggui-color-primary-600)' : 'none',
                  transition: 'all 200ms ease',
                }}
              >
                <Text variant="caption" style={{ opacity: 0.7 }}>
                  {element.atomicNumber}
                </Text>
                <Text variant="bodyLarge" weight="bold" style={{ fontSize: '1.5em' }}>
                  {element.symbol}
                </Text>
              </Card>
            );
          })}
        </Box>

        {/* Detail panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-4)">
              <Row justify="between" align="center">
                <Heading level={2}>{selectedElement.name || 'Unknown'}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  ×
                </Button>
              </Row>

              <Divider />

              <Row gap="var(--ggui-spacing-8)" wrap>
                <Stack gap="var(--ggui-spacing-3)">
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Symbol</Text>
                    <Text variant="bodyLarge" weight="bold">{selectedElement.symbol}</Text>
                  </Box>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Number</Text>
                    <Text variant="bodyLarge">{selectedElement.atomicNumber}</Text>
                  </Box>
                </Stack>

                <Stack gap="var(--ggui-spacing-3)">
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Atomic Weight</Text>
                    <Text variant="bodyLarge">{selectedElement.atomicWeight?.toFixed(2) || 'N/A'}</Text>
                  </Box>
                  <Box>
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category</Text>
                    <Badge variant="primary" size="md">
                      {selectedElement.category || 'Unknown'}
                    </Badge>
                  </Box>
                </Stack>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Empty state */}
        {filteredElements.length === 0 && (
          <Card padding="var(--ggui-spacing-6)" shadow="sm">
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name="search" size={32} color="var(--ggui-color-onSurfaceVariant)" />
              <Text color="var(--ggui-color-onSurfaceVariant)">
                No elements found matching "{searchQuery}"
              </Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

