import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for quantity and active tab
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Compute stock status
  const stockStatus = useMemo(() => {
    if (!props.product.stock) return 'Out of Stock';
    return props.product.stock > 10 ? 'In Stock' : 'Low Stock';
  }, [props.product.stock]);

  // Handle Add to Cart
  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [props.product.id, quantity, addToCart]);

  // Render star rating
  const renderStars = (rating: number | undefined) => {
    if (!rating) return null;
    const stars = [];
    for (let i = 1; i <= 5; i++) {
      stars.push(
        <Icon
          key={i}
          name={i <= Math.round(rating) ? 'star' : 'star'}
          size={16}
          color={i <= Math.round(rating) ? 'var(--ggui-color-warning-500)' : 'var(--ggui-color-outlineVariant)'}
        />
      );
    }
    return <Row gap="var(--ggui-spacing-1)" align="center">{stars}</Row>;
  };

  // Parse specifications and reviews
  const specArray = Array.isArray(props.product.specifications) ? props.product.specifications : [];
  const reviewArray = Array.isArray(props.product.reviews) ? props.product.reviews : [];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image, Title, Price, Rating, Stock */}
        <Row gap="var(--ggui-spacing-8)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-primary-50)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', minHeight: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack align="center" gap="var(--ggui-spacing-2)">
              <Icon name="image" size={48} color="var(--ggui-color-primary-400)" />
              <Text variant="bodySmall" color="var(--ggui-color-primary-700)" align="center">
                {props.product.name || 'Product Image'}
              </Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Stack gap="var(--ggui-spacing-2)">
              <Heading level={1}>{props.product.name || 'Product Name'}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-primary-600)" weight="semibold">
                {props.product.currency || '$'}{props.product.price?.toFixed(2) || '0.00'}
              </Text>
            </Stack>

            {/* Rating */}
            <Row gap="var(--ggui-spacing-2)" align="center">
              {renderStars(props.product.rating)}
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                ({props.product.reviewCount || 0} reviews)
              </Text>
            </Row>

            {/* Stock Status */}
            <Badge variant={stockStatus === 'In Stock' ? 'success' : stockStatus === 'Low Stock' ? 'warning' : 'error'}>
              {stockStatus}
            </Badge>
          </Stack>
        </Row>

        {/* Middle Section: Tabs */}
        <Stack gap="var(--ggui-spacing-4)">
          <Tabs
            variant="line"
            items={[
              {
                key: 'description',
                label: 'Description',
                content: (
                  <Text>{props.product.description || 'No description available'}</Text>
                ),
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  specArray.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'key', header: 'Property' },
                        { key: 'value', header: 'Value' },
                      ]}
                      data={specArray.map((spec: any) => ({
                        key: spec.key || '',
                        value: spec.value || '',
                      }))}
                    />
                  ) : (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>
                  )
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  reviewArray.length > 0 ? (
                    <Stack gap="var(--ggui-spacing-4)">
                      {reviewArray.map((review: any) => (
                        <Card key={review.id || Math.random()} padding="var(--ggui-spacing-4)" shadow="sm">
                          <Stack gap="var(--ggui-spacing-2)">
                            <Row justify="between" align="center">
                              <Text weight="semibold">{review.author || 'Anonymous'}</Text>
                              {renderStars(review.rating)}
                            </Row>
                            <Text>{review.text || review.content || 'No text'}</Text>
                            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                              {review.date ? new Date(review.date).toLocaleDateString() : 'Date unknown'}
                            </Text>
                          </Stack>
                        </Card>
                      ))}
                    </Stack>
                  ) : (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>
                  )
                ),
              },
            ]}
            activeKey={activeTab}
            onChange={setActiveTab}
          />
        </Stack>

        {/* Bottom Section: Quantity Selector & Add to Cart */}
        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Text variant="label">Quantity:</Text>
              <Row gap="var(--ggui-spacing-2)" align="center">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setQuantity(Math.max(1, quantity - 1))}
                  disabled={quantity <= 1}
                >
                  −
                </Button>
                <Text style={{ minWidth: '40px', textAlign: 'center' }}>{quantity}</Text>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setQuantity(quantity + 1)}
                  disabled={quantity >= (props.product.stock || 0)}
                >
                  +
                </Button>
              </Row>
            </Stack>
            <Button
              variant="primary"
              size="lg"
              onClick={handleAddToCart}
              disabled={!props.product.stock || props.product.stock === 0}
            >
              Add to Cart
            </Button>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}
}

