interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [inputText, setInputText] = useState<string>('');
  const [displayMessages, setDisplayMessages] = useState<Array<{ sender?: string; text?: string; timestamp?: string }>>(props.messages);
  const [activeTyping, setActiveTyping] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    if (messagesEndRef.current) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, []);

  // Append new message from stream
  useEffect(() => {
    if (message.latest) {
      setDisplayMessages((prev) => [...prev, message.latest!]);
      scrollToBottom();
    }
  }, [message.latest, scrollToBottom]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active) {
        setActiveTyping({ sender: typing.latest.sender });
      } else {
        setActiveTyping(null);
      }
    }
  }, [typing.latest]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (inputText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: inputText, timestamp });
      setInputText('');
    }
  }, [inputText, sendMessage]);

  // Handle Enter key in input
  const handleKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ text?: string; timestamp?: string }>;
    }> = [];

    displayMessages.forEach((msg) => {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push({ text: msg.text, timestamp: msg.timestamp });
      } else {
        groups.push({
          sender: msg.sender,
          messages: [{ text: msg.text, timestamp: msg.timestamp }],
        });
      }
    });

    return groups;
  }, [displayMessages]);

  // Format timestamp for display
  const formatTime = (timestamp?: string): string => {
    if (!timestamp) return '';
    try {
      const date = new Date(timestamp);
      return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    } catch {
      return '';
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg" border={true}>
        <Stack gap="var(--ggui-spacing-4)" direction="vertical" style={{ height: '600px', display: 'flex', flexDirection: 'column' }}>
          {/* Header */}
          <Row gap="var(--ggui-spacing-3)" align="center" justify="between">
            <Stack gap="var(--ggui-spacing-2)" direction="horizontal" align="center">
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="primary" size="sm">{props.participantCount} participants</Badge>
            </Stack>
            {activeTyping && activeTyping.sender && (
              <Stack gap="var(--ggui-spacing-1)" direction="horizontal" align="center">
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{activeTyping.sender} is typing</Text>
                <Spinner size={16} color="var(--ggui-color-primary-600)" />
              </Stack>
            )}
          </Row>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Message list */}
          <Stack
            gap="var(--ggui-spacing-3)"
            direction="vertical"
            align="stretch"
            style={{
              flex: 1,
              overflowY: 'auto',
              paddingRight: 'var(--ggui-spacing-2)',
              paddingLeft: 'var(--ggui-spacing-2)',
            }}
          >
            {groupedMessages.length === 0 ? (
              <Box
                padding="var(--ggui-spacing-4)"
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  flex: 1,
                }}
              >
                <Text color="var(--ggui-color-onSurfaceVariant)" variant="caption">
                  No messages yet. Start the conversation!
                </Text>
              </Box>
            ) : (
              groupedMessages.map((group, groupIdx) => {
                const isCurrentUser = group.sender === props.currentUser;
                const isOwnMessage = isCurrentUser;

                return (
                  <Stack
                    key={groupIdx}
                    gap="var(--ggui-spacing-1)"
                    direction="vertical"
                    align={isOwnMessage ? 'end' : 'start'}
                  >
                    {!isOwnMessage && (
                      <Text variant="label" color="var(--ggui-color-onSurface)" style={{ fontSize: 'var(--ggui-font-size-sm)' }}>
                        {group.sender || 'Unknown'}
                      </Text>
                    )}
                    {group.messages.map((msg, msgIdx) => (
                      <Box
                        key={msgIdx}
                        padding="var(--ggui-spacing-3)"
                        background={isOwnMessage ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                        borderRadius="var(--ggui-shape-radius-lg)"
                        style={{
                          maxWidth: '60%',
                          wordWrap: 'break-word',
                          overflowWrap: 'break-word',
                        }}
                      >
                        <Text
                          variant="body"
                          color={isOwnMessage ? 'white' : 'var(--ggui-color-onSurface)'}
                        >
                          {msg.text || ''}
                        </Text>
                        {msg.timestamp && (
                          <Text
                            variant="caption"
                            color={isOwnMessage ? 'rgba(255, 255, 255, 0.7)' : 'var(--ggui-color-onSurfaceVariant)'}
                            style={{ marginTop: 'var(--ggui-spacing-1)', display: 'block' }}
                          >
                            {formatTime(msg.timestamp)}
                          </Text>
                        )}
                      </Box>
                    ))}
                  </Stack>
                );
              })
            )}
            <div ref={messagesEndRef} />
          </Stack>

          <Divider orientation="horizontal" margin="var(--ggui-spacing-2)" />

          {/* Input area */}
          <Row gap="var(--ggui-spacing-2)" align="end" justify="start">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={inputText}
                onChange={setInputText}
                onKeyDown={handleKeyDown}
              />
            </Box>
            <Button
              variant="primary"
              onClick={handleSendMessage}
              disabled={!inputText.trim()}
              rightIcon={<Icon name="send" size={16} />}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

