// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  stocks: Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>; // Array of stocks with symbol, name, price, change, changePercent
}


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: Updated price data for one or more stocks */
type StreamPriceUpdate = { symbol?: string; price?: number; change?: number; changePercent?: number };

/** Stream event: Market open/closed status update */
type StreamMarketStatus = { status?: 'open' | 'closed' | 'pre-market' | 'after-hours'; timestamp?: string };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const updateKeysRef = useRef<Record<string, number>>({});

  // Merge price updates from stream into stock data
  useEffect(() => {
    if (priceUpdate.latest) {
      setStocks((prevStocks) => {
        const updated = prevStocks.map((stock) => {
          if (stock.symbol === priceUpdate.latest?.symbol) {
            return {
              ...stock,
              price: priceUpdate.latest.price ?? stock.price,
              change: priceUpdate.latest.change ?? stock.change,
              changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
        // Mark this stock for animation key update
        if (priceUpdate.latest?.symbol) {
          updateKeysRef.current[priceUpdate.latest.symbol] =
            (updateKeysRef.current[priceUpdate.latest.symbol] || 0) + 1;
        }
        setLastUpdated(new Date());
        return updated;
      });
    }
  }, [priceUpdate.latest]);

  // Format currency
  const formatPrice = useCallback((price: number | undefined) => {
    if (price === undefined) return 'N/A';
    return `$${price.toFixed(2)}`;
  }, []);

  // Format percentage
  const formatPercent = useCallback((percent: number | undefined) => {
    if (percent === undefined) return 'N/A';
    const sign = percent > 0 ? '+' : '';
    return `${sign}${percent.toFixed(2)}%`;
  }, []);

  // Get color based on change direction
  const getChangeColor = useCallback((change: number | undefined) => {
    if (change === undefined) return 'var(--ggui-color-onSurface)';
    return change > 0 ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';
  }, []);

  // Get border color based on change direction
  const getChangeBorderColor = useCallback((change: number | undefined) => {
    if (change === undefined) return 'var(--ggui-color-outlineVariant)';
    return change > 0 ? 'var(--ggui-color-success-200)' : 'var(--ggui-color-error-200)';
  }, []);

  // Get background color for change highlight
  const getChangeBackgroundColor = useCallback((change: number | undefined) => {
    if (change === undefined) return 'transparent';
    return change > 0 ? 'var(--ggui-color-success-50)' : 'var(--ggui-color-error-50)';
  }, []);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header with title and last updated timestamp */}
        <Box>
          <Row align="center" justify="between">
            <Heading level={1}>Market Watch</Heading>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
              Last Updated: {lastUpdated.toLocaleTimeString()}
            </Text>
          </Row>
        </Box>

        {/* Stock cards grid */}
        <Box>
          {stocks && stocks.length > 0 ? (
            <div
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
                gap: 'var(--ggui-spacing-6)',
              }}
            >
              {stocks.map((stock) => {
                const updateKey = updateKeysRef.current[stock.symbol || ''] || 0;
                const changeColor = getChangeColor(stock.change);
                const changeBorderColor = getChangeBorderColor(stock.change);
                const changeBackgroundColor = getChangeBackgroundColor(stock.change);
                const arrowIcon = stock.change && stock.change > 0 ? '▲' : stock.change && stock.change < 0 ? '▼' : '';

                return (
                  <Card
                    key={`${stock.symbol}-${updateKey}`}
                    padding="var(--ggui-spacing-5)"
                    shadow="md"
                    border={true}
                    radius="lg"
                    style={{
                      borderColor: changeBorderColor,
                      borderWidth: '1px',
                      animation: updateKey > 0 ? 'ggui-flash 300ms ease-out' : 'none',
                      '--ggui-flash-color': changeBackgroundColor,
                    } as React.CSSProperties}
                  >
                    <Stack gap="var(--ggui-spacing-3)">
                      {/* Ticker symbol - large and bold */}
                      <Heading level={3} color="var(--ggui-color-onSurface)">
                        {stock.symbol || 'N/A'}
                      </Heading>

                      {/* Company name */}
                      <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
                        {stock.name || 'Unknown Company'}
                      </Text>

                      {/* Current price */}
                      <Text
                        variant="bodyLarge"
                        weight="semibold"
                        color="var(--ggui-color-onSurface)"
                      >
                        {formatPrice(stock.price)}
                      </Text>

                      {/* Change amount and percentage with arrow */}
                      <Row align="center" gap="var(--ggui-spacing-2)">
                        <Text variant="body" color={changeColor} weight="semibold">
                          {stock.change !== undefined && stock.change > 0 ? '+' : ''}
                          {stock.change !== undefined ? stock.change.toFixed(2) : 'N/A'}
                        </Text>
                        <Text variant="body" color={changeColor} weight="semibold">
                          {arrowIcon}
                        </Text>
                        <Text variant="body" color={changeColor} weight="semibold">
                          {formatPercent(stock.changePercent)}
                        </Text>
                      </Row>
                    </Stack>
                  </Card>
                );
              })}
            </div>
          ) : (
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
              No stocks to display
            </Text>
          )}
        </Box>
      </Stack>
    </Container>
  );
}

