interface Props {
  initialProfile: { name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string }; // Pre-filled profile data for editing (all fields optional)
  avatarOptions: string[]; // Available avatar emojis to choose from
  roleOptions: string[]; // Available role options for the dropdown
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all profile data when user completes onboarding */
type ActionCompletePayload = { name: string; email: string; avatar: string; role: string; emailNotifications: boolean; theme: string };





// Step indicator component
function StepIndicator({ currentStep, totalSteps }: { currentStep: number; totalSteps: number }) {
  return (
    <Stack gap="var(--ggui-spacing-4)" align="center" style={{ marginBottom: 'var(--ggui-spacing-6)' }}>
      <Row gap="var(--ggui-spacing-3)" justify="center" align="center">
        {Array.from({ length: totalSteps }).map((_, index) => (
          <React.Fragment key={index}>
            <Box
              padding="var(--ggui-spacing-3)"
              borderRadius="var(--ggui-shape-radius-full)"
              background={
                index + 1 < currentStep
                  ? 'var(--ggui-color-success-500)'
                  : index + 1 === currentStep
                  ? 'var(--ggui-color-primary-600)'
                  : 'var(--ggui-color-outlineVariant)'
              }
              style={{ display: 'flex', alignItems: 'center', justifyContent: 'center' }}
            >
              <Text variant="label" color="white" style={{ fontWeight: 'bold' }}>
                {index + 1}
              </Text>
            </Box>
            {index < totalSteps - 1 && (
              <Box
                style={{
                  width: '40px',
                  height: '2px',
                  background:
                    index + 1 < currentStep
                      ? 'var(--ggui-color-success-500)'
                      : 'var(--ggui-color-outlineVariant)',
                }}
              />
            )}
          </React.Fragment>
        ))}  
      </Row>
      <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
        Step {currentStep} of {totalSteps}
      </Text>
    </Stack>
  );
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const complete = useAction<ActionCompletePayload>('complete'); // Called with all profile data when user completes onboarding

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState({
    name: props.initialProfile?.name || '',
    email: props.initialProfile?.email || '',
    avatar: props.initialProfile?.avatar || (props.avatarOptions?.[0] || '👤'),
    role: props.initialProfile?.role || (props.roleOptions?.[0] || ''),
    emailNotifications: props.initialProfile?.emailNotifications !== false,
    theme: props.initialProfile?.theme || 'light',
  });

  // Validation state
  const [errors, setErrors] = useState({ name: '', email: '' });

  // Email validation helper
  const isValidEmail = (email: string): boolean => {
    return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
  };

  // Validation for step 1
  const isStep1Valid = useMemo(() => {
    return formData.name.trim() !== '' && isValidEmail(formData.email);
  }, [formData.name, formData.email]);

  // Handle field changes
  const handleFieldChange = useCallback((field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (field === 'name') {
      setErrors((prev) => ({ ...prev, name: '' }));
    }
    if (field === 'email') {
      setErrors((prev) => ({ ...prev, email: '' }));
    }
  }, []);

  // Handle next step
  const handleNext = useCallback(() => {
    if (currentStep === 1) {
      const nameError = formData.name.trim() === '' ? 'Name is required' : '';
      const emailError = !isValidEmail(formData.email) ? 'Please enter a valid email' : '';
      if (nameError || emailError) {
        setErrors({ name: nameError, email: emailError });
        return;
      }
    }
    setCurrentStep((prev) => Math.min(prev + 1, 3));
  }, [currentStep, formData.name, formData.email]);

  // Handle back button
  const handleBack = useCallback(() => {
    setCurrentStep((prev) => Math.max(prev - 1, 1));
  }, []);

  // Handle complete setup
  const handleComplete = useCallback(() => {
    complete({
      name: formData.name,
      email: formData.email,
      avatar: formData.avatar,
      role: formData.role,
      emailNotifications: formData.emailNotifications,
      theme: formData.theme,
    });
  }, [formData, complete]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)" align="stretch">
        {/* Step Indicator */}
        <StepIndicator currentStep={currentStep} totalSteps={3} />

        {/* Step 1: Profile Setup */}
        {currentStep === 1 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2}>Profile Setup</Heading>

              {/* Name Input */}
              <Input
                label="Full Name"
                placeholder="Enter your full name"
                value={formData.name}
                onChange={(value) => handleFieldChange('name', value)}
                error={errors.name}
                required
              />

              {/* Email Input */}
              <Input
                label="Email Address"
                type="email"
                placeholder="your@example.com"
                value={formData.email}
                onChange={(value) => handleFieldChange('email', value)}
                error={errors.email}
                required
              />

              {/* Avatar Selection */}
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Choose Avatar
                </Text>
                <Row gap="var(--ggui-spacing-3)" wrap>
                  {props.avatarOptions?.map((avatarOption) => (
                    <Box
                      key={avatarOption}
                      as={Clickable}
                      onClick={() => handleFieldChange('avatar', avatarOption)}
                      padding="var(--ggui-spacing-2)"
                      borderRadius="var(--ggui-shape-radius-md)"
                      background={
                        formData.avatar === avatarOption
                          ? 'var(--ggui-color-primary-100)'
                          : 'var(--ggui-color-surfaceVariant)'
                      }
                      style={{
                        border:
                          formData.avatar === avatarOption
                            ? '2px solid var(--ggui-color-primary-600)'
                            : '2px solid transparent',
                        cursor: 'pointer',
                        transition: 'all 200ms ease-in-out',
                      }}
                      hoverStyle={{ opacity: 0.8 }}
                    >
                      <Text size="3xl">{avatarOption}</Text>
                    </Box>
                  ))}  
                </Row>
              </Stack>

              {/* Navigation */}
              <Row gap="var(--ggui-spacing-3)" justify="end">
                <Button variant="outline" onClick={handleNext}>
                  Next
                </Button>
              </Row>
            </Stack>
          </Card>
        )}

        {/* Step 2: Preferences */}
        {currentStep === 2 && (
          <Card padding="var(--ggui-spacing-6)" shadow="md">
            <Stack gap="var(--ggui-spacing-6)">
              <Heading level={2}>Preferences</Heading>

              {/* Role Selection */}
              <Select
                label="Role"
                value={formData.role}
                onChange={(value) => handleFieldChange('role', value)}
                options={props.roleOptions?.map((role) => ({
                  value: role,
                  label: role,
                })) || []}
                placeholder="Select your role"
              />

              {/* Email Notifications Toggle */}
              <Toggle
                label="Email Notifications"
                checked={formData.emailNotifications}
                onChange={(checked) => handleFieldChange('emailNotifications', checked)}
              />

              {/* Theme Preference */}
              <Stack gap="var(--ggui-spacing-3)">
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                  Theme Preference
                </Text>
                <Row gap="var(--ggui-spacing-4)">
                  {['light', 'dark'].map((themeOption) => (
                    <Box
                      key={themeOption}
                      as={Clickable}
                      onClick={() => handleFieldChange('theme', themeOption)}
