}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [currentStep, setCurrentStep] = useState<number>(1);
  const [name, setName] = useState<string>('');
  const [email, setEmail] = useState<string>('');
  const [satisfaction, setSatisfaction] = useState<string>('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState<string>('');
  const [nameTouched, setNameTouched] = useState<boolean>(false);
  const [emailTouched, setEmailTouched] = useState<boolean>(false);
  const [submitted, setSubmitted] = useState<boolean>(false);

  const safeFeatureOptions = Array.isArray(props.featureOptions) ? props.featureOptions : [];
  const safeSatisfactionLabels = Array.isArray(props.satisfactionLabels) ? props.satisfactionLabels : [];

  const nameError = nameTouched && name.trim().length === 0 ? 'Name is required.' : '';
  const emailError = emailTouched && email.trim().length === 0
    ? 'Email is required.'
    : emailTouched && !emailRegex.test(email.trim())
      ? 'Please enter a valid email address.'
      : '';

  const step1Valid = name.trim().length > 0 && emailRegex.test(email.trim());
  const step2Valid = satisfaction !== '';
  const isFinalReviewStep = currentStep === 5;
  const progressValue = (currentStep / 5) * 100;
  const ratingOptions = useMemo(() => {
    const fallback = ['1', '2', '3', '4', '5'];
    const labels = safeSatisfactionLabels.length >= 5 ? safeSatisfactionLabels.slice(0, 5) : fallback;
    return ['1', '2', '3', '4', '5'].map((value, index) => ({
      value,
      label: labels[index] || `Rating ${value}`
    }));
  }, [safeSatisfactionLabels]);

  const canGoNext = useMemo(() => {
    if (currentStep === 1) return step1Valid;
    if (currentStep === 2) return step2Valid;
    if (currentStep === 3) return true;
    if (currentStep === 4) return true;
    return true;
  }, [currentStep, step1Valid, step2Valid]);

  const toggleFeature = useCallback((feature: string, checked: boolean) => {
    if (checked) {
      setSelectedFeatures((prev) => (prev.includes(feature) ? prev : [...prev, feature]));
      return;
    }
    setSelectedFeatures((prev) => prev.filter((item) => item !== feature));
  }, []);

  const handleNext = useCallback(() => {
    if (currentStep < 5 && canGoNext) {
      setCurrentStep((prev) => prev + 1);
    }
  }, [currentStep, canGoNext]);

  const handleBack = useCallback(() => {
    if (currentStep > 1) {
      setCurrentStep((prev) => prev - 1);
    }
  }, [currentStep]);

  const handleSubmit = useCallback(() => {
    if (!step1Valid || !step2Valid) return;
    submit({
      name: name.trim(),
      email: email.trim(),
      satisfaction: Number(satisfaction),
      features: selectedFeatures,
      comments: comments.trim()
    });
    setSubmitted(true);
  }, [step1Valid, step2Valid, submit, name, email, satisfaction, selectedFeatures, comments]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-5)">
          <Stack gap="var(--ggui-spacing-2)">
            <Row justify="between" align="center">
              <Heading level={3}>Survey</Heading>
              <Badge variant="primary">Step {currentStep} of 5</Badge>
            </Row>
            <Progress value={progressValue} max={100} variant="default" />
          </Stack>

          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Your Information</Heading>
              <Input
                label="Name"
                value={name}
                onChange={(value) => {
                  if (!nameTouched) setNameTouched(true);
                  setName(value);
                }}
                required
                error={nameError || undefined}
                placeholder="Enter your full name"
              />
              <Input
                label="Email"
                type="email"
                value={email}
                onChange={(value) => {
                  if (!emailTouched) setEmailTouched(true);
                  setEmail(value);
                }}
                required
                error={emailError || undefined}
                placeholder="you@example.com"
              />
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={satisfaction}
                onChange={setSatisfaction}
                options={ratingOptions}
                direction="vertical"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Feature Interests</Heading>
              {safeFeatureOptions.length === 0 ? (
                <Alert variant="info" title="No features available">
                  Feature options are currently unavailable.
                </Alert>
              ) : (
                <Stack gap="var(--ggui-spacing-2)">
                  {safeFeatureOptions.map((feature) => (
                    <Checkbox
                      key={feature}
                      label={feature}
                      checked={selectedFeatures.includes(feature)}
                      onChange={(checked) => toggleFeature(feature, checked)}
                    />
                  ))}
                </Stack>
              )}
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Additional Comments</Heading>
              <TextArea
                label="Comments"
                value={comments}
                onChange={setComments}
                placeholder="Share any additional thoughts (optional)"
                maxLength={500}
                showCount
                helperText="Optional"
                rows={6}
              />
            </Stack>
          )}

          {currentStep === 5 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={4}>Review Your Answers</Heading>
              <Card padding="var(--ggui-spacing-4)" border radius="md" shadow="none">
                <Stack gap="var(--ggui-spacing-3)">
                  <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Row justify="between"><Text variant="label">Satisfaction</Text><Text>{ratingOptions.find((r) => r.value === satisfaction)?.label || '-'}</Text></Row>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Features</Text>
                    <Text>{selectedFeatures.length > 0 ? selectedFeatures.join(', ') : 'None selected'}</Text>
                  </Stack>
                  <Divider margin="var(--ggui-spacing-1)" />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Comments</Text>
                    <Text>{comments.trim().length > 0 ? comments : 'No comments provided'}</Text>
                  </Stack>
                </Stack>
              </Card>
              {submitted && (
                <Alert variant="success" title="Submitted">
                  Your responses have been submitted successfully.
                </Alert>
              )}
            </Stack>
          )}

          <Divider margin="var(--ggui-spacing-1)" />
          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={currentStep === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {!isFinalReviewStep ? (
                <Button variant="primary" onClick={handleNext} disabled={!canGoNext}>
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} disabled={!step1Valid || !step2Valid}>
                  Submit Survey
                </Button>
              )}
            </Row>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

