    const incoming = toSafeTask(taskChanged.latest.task, 0);
    if (taskChanged.latest.action === 'delete') {
      setTasksState((prev) => prev.filter((task) => task.id !== incoming.id));
      return;
    }
    setTasksState((prev) => {
      const idx = prev.findIndex((task) => task.id === incoming.id);
      if (idx === -1) {
