    }));
    return requiredOrder.map((id) => {
      const fromProps = normalized.find((column) => column.id === id);
      const fallback = DEFAULT_COLUMNS.find((column) => column.id === id);
      return {
        id,
        name: (fromProps && fromProps.name) || (fallback && fallback.name) || id,
