              <Badge variant="primary">Total: {totalTasks}</Badge>
              <Badge variant="success">Completed: {completedCount}</Badge>
              <Badge variant={taskChanged.latest ? 'info' : 'default'}>{taskChanged.latest ? 'Live updates on' : 'Waiting for updates'}</Badge>
            </Row>
