type ProductSpecification = { key?: string; label?: string; name?: string; value?: string | number | boolean };
type ProductReview = { author?: string; rating?: number; text?: string; date?: string };

function formatPrice(value: number | undefined, currency: string | undefined): string {
  if (typeof value !== 'number') return '—';
  try {
    return new Intl.NumberFormat(undefined, {
      style: 'currency',
      currency: currency || 'USD',
      currencyDisplay: 'symbol',
    }).format(value);
  } catch {
    return value.toFixed(2);
  }
}

function renderStars(rating: number | undefined): string {
  const safeRating = Math.max(0, Math.min(5, Math.round(rating ?? 0)));
  return `${'★'.repeat(safeRating)}${'☆'.repeat(5 - safeRating)}`;
}

