              &nbsp;
            </Text>
          )}

          <Box
            padding="var(--ggui-spacing-3)"
            background="var(--ggui-color-surface)"
            borderRadius="var(--ggui-shape-radius-md)"
          >
            <Stack
              gap="var(--ggui-spacing-3)"
            >
              <Box>
                <div
                  ref={listRef}
                  style={{
                    maxHeight: '55vh',
                    overflowY: 'auto',
                    display: 'flex',
                    flexDirection: 'column',
                    gap: 'var(--ggui-spacing-3)',
                    paddingRight: 'var(--ggui-spacing-1)'
                  }}
                >
                  {groupedMessages.length === 0 ? (
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                      No messages yet.
                    </Text>
                  ) : (
                    groupedMessages.map((group, groupIndex) => {
                      const isMine = group.sender === props.currentUser;
                      return (
                        <Stack key={`${group.sender || 'unknown'}-${groupIndex}`} gap="var(--ggui-spacing-1)" align={isMine ? 'end' : 'start'}>
                          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                            {group.sender || 'Unknown'}
                          </Text>
                          {group.items.map((msg, idx) => (
                            <Box
                              key={`${groupIndex}-${idx}-${msg.timestamp || 't'}`}
                              padding="var(--ggui-spacing-2)"
                              background={isMine ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
                              borderRadius="var(--ggui-shape-radius-md)"
                            >
                              <Stack gap="var(--ggui-spacing-1)">
                                <Text
                                  variant="bodySmall"
                                  color={isMine ? 'var(--ggui-color-surface)' : 'var(--ggui-color-onSurface)'}
                                >
                                  {msg.text || ''}
                                </Text>
                                <Text
                                  variant="caption"
                                  color={isMine ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-onSurfaceVariant)'}
                                  align={isMine ? 'right' : 'left'}
                                >
                                  {formatTime(msg.timestamp)}
                                </Text>
                              </Stack>
                            </Box>
                          ))}
                        </Stack>
                      );
                    })
                  )}
                </div>
              </Box>
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-2)" color="var(--ggui-color-outlineVariant)" />

          <Row gap="var(--ggui-spacing-2)" align="end">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type your message..."
                value={draft}
                onChange={setDraft}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleSend();
                  }
                }}
              />
            </Box>
            <Button variant="primary" onClick={handleSend} disabled={!draft.trim()}>
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>

  );
}

