// Place helper components here if needed
const formatCurrency = (value?: number): string => `$${(value ?? 0).toFixed(2)}`;
const formatSigned = (value?: number): string => {
  const safe = value ?? 0;
  const sign = safe >= 0 ? '+' : '';
  return `${sign}${safe.toFixed(2)}`;
};
const formatPercent = (value?: number): string => {
  const safe = value ?? 0;
  const sign = safe >= 0 ? '+' : '';
