};

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocksState, setStocksState] = useState<Array<{ symbol?: string; name?: string; price?: number; change?: number; changePercent?: number }>>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [now, setNow] = useState<Date>(new Date());
  const [flashMap, setFlashMap] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => setNow(new Date()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    setStocksState((prev) => {
      const next = (prev ?? []).map((stock) => {
        if (stock.symbol !== priceUpdate.latest?.symbol) {
          return stock;
        }
        return {
          ...stock,
          price: priceUpdate.latest.price ?? stock.price,
          change: priceUpdate.latest.change ?? stock.change,
          changePercent: priceUpdate.latest.changePercent ?? stock.changePercent,
        };
      });
      const hasSymbol = next.some((stock) => stock.symbol === priceUpdate.latest?.symbol);
      if (!hasSymbol) {
        next.push({
          symbol: priceUpdate.latest.symbol,
          name: priceUpdate.latest.symbol,
          price: priceUpdate.latest.price,
          change: priceUpdate.latest.change,
          changePercent: priceUpdate.latest.changePercent,
        });
      }
      return next;
    });

    setLastUpdated(new Date());
    setFlashMap((prev) => ({
      ...prev,
      [priceUpdate.latest?.symbol ?? '']: Date.now(),
    }));
  }, [priceUpdate.latest]);

  useEffect(() => {
    if (!marketStatus.latest?.timestamp) {
      return;
    }
    setLastUpdated(new Date(marketStatus.latest.timestamp));
  }, [marketStatus.latest]);

  const statusVariant = useMemo(() => {
    if (marketStatus.latest?.status === 'open') return 'success';
    if (marketStatus.latest?.status === 'closed') return 'error';
    return 'warning';
  }, [marketStatus.latest]);

  const statusLabel = useMemo(() => marketStatus.latest?.status ?? 'live', [marketStatus.latest]);

  const stocksToRender = useMemo(() => stocksState ?? [], [stocksState]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border>
          <Row align="center" justify="between" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onSurface)">Market Watch</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {lastUpdated.toLocaleTimeString()}
              </Text>
            </Stack>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Badge variant={statusVariant}>{statusLabel}</Badge>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Clock: {now.toLocaleTimeString()}
              </Text>
            </Row>
          </Row>
        </Card>

        {stocksToRender.length === 0 ? (
          <Alert variant="info" title="No stock data">No stocks available to display.</Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stocksToRender.map((stock, index) => {
              const positive = (stock.change ?? 0) >= 0;
              const symbolKey = stock.symbol ?? `stock-${index}`;
              const isFlashing = flashMap[symbolKey] && Date.now() - flashMap[symbolKey] < 1000;

              return (
                <Card
                  key={symbolKey}
                  padding="var(--ggui-spacing-4)"
                  border
                  shadow="sm"
                  style={
                    {
                      borderColor: positive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)',
                      background: isFlashing
                        ? positive
                          ? 'var(--ggui-color-success-100)'
                          : 'var(--ggui-color-error-100)'
                        : 'var(--ggui-color-surface)',
                      transition: 'background-color 300ms ease-in-out, border-color 200ms ease-in-out',
                    } as React.CSSProperties
                  }
                >
                  <Stack gap="var(--ggui-spacing-2)">
                    <Heading level={3} color="var(--ggui-color-onSurface)">{stock.symbol ?? '—'}</Heading>
                    <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{stock.name ?? 'Unknown Company'}</Text>
                    <Text variant="bodyLarge" weight="bold" color="var(--ggui-color-onSurface)">
                      {formatCurrency(stock.price)}
                    </Text>
                    <Row align="center" gap="var(--ggui-spacing-2)">
                      <Text
                        variant="bodySmall"
                        weight="medium"
                        color={positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                      >
                        {formatSigned(stock.change)}
                      </Text>
                      <Text
                        variant="bodySmall"
                        weight="medium"
                        color={positive ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)'}
                      >
                        {positive ? '▲' : '▼'} {formatPercent(stock.changePercent)}
                      </Text>
                    </Row>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        )}
      </Stack>
    </Container>

  );
}

