            }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    value={name}
                    onChange={setName}
                    placeholder="Enter your name"
                    required
                    error={nameError || undefined}
                  />
                  <Input
                    label="Email"
                    type="email"
                    value={email}
                    onChange={setEmail}
                    placeholder="you@example.com"
                    required
                    error={emailError || undefined}
                  />
                  <Stack gap="var(--ggui-spacing-2)">
                    <Text variant="label">Choose an avatar</Text>
                    <Row gap="var(--ggui-spacing-3)" wrap>
                      {resolvedAvatarOptions.map((option) => (
                        <Card
                          key={option}
                          as={Clickable}
                          onClick={() => setAvatar(option)}
                          padding="var(--ggui-spacing-3)"
                          border
                          shadow="none"
                          radius="md"
                          style={{
                            borderColor: avatar === option ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-outline)',
                            background: avatar === option ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)',
                          }}
                        >
                          <Text size="2xl" align="center">{option}</Text>
                        </Card>
                      ))}
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={resolvedRoleOptions.map((option) => ({ value: option, label: option }))}
                    placeholder="Select your role"
                    required
                    error={role.trim().length === 0 ? 'Role is required' : undefined}
                  />
                  <Toggle
                    label="Email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                  />
                  <Toggle
                    label="Dark theme"
                    checked={theme === 'dark'}
                    onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                  />
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                    Selected theme: {theme === 'dark' ? 'Dark' : 'Light'}
                  </Text>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Card padding="var(--ggui-spacing-4)" shadow="none" border radius="md">
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row justify="between"><Text variant="label">Name</Text><Text>{name || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email</Text><Text>{email || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Avatar</Text><Text>{avatar || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Role</Text><Text>{role || '-'}</Text></Row>
                      <Row justify="between"><Text variant="label">Email Notifications</Text><Text>{emailNotifications ? 'On' : 'Off'}</Text></Row>
                      <Row justify="between"><Text variant="label">Theme</Text><Text>{theme === 'dark' ? 'Dark' : 'Light'}</Text></Row>
                    </Stack>
                  </Card>
                  {showSubmitted && (
                    <Alert variant="success" title="Setup completed">
                      Your onboarding details were submitted successfully.
                    </Alert>
                  )}
                </Stack>
              )}
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Button variant="outline" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 && (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                  Next
                </Button>
              )}
              {step === 3 && (
                <>
                  <Button variant="ghost" onClick={handleBack}>
                    Go Back
                  </Button>
                  <Button variant="primary" onClick={handleComplete} disabled={!isStepOneValid || !isStepTwoValid}>
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
